const inputCountry = ($node["Webhook: Job Request"].json.query.country || 'sweden').toLowerCase();
const inputCity = $node["Webhook: Job Request"].json.query.city || '';

// 🌍 GLOBAL STRATEGIC MAPPING (V16.0)
const countryMap = {
  'sweden': 'se',
  'germany': 'de',
  'united kingdom': 'gb',
  'norway': 'no',
  'finland': 'fi',
  'denmark': 'dk',
  'sri lanka': 'lk',
  'united states': 'us',
  'canada': 'ca',
  'australia': 'au',
  'france': 'fr',
  'netherlands': 'nl'
};

const countryCode = countryMap[inputCountry] || inputCountry;

// 🛰️ DYNAMIC PROVIDER STRATEGY
// Adzuna only supports ~19 countries. Fallback to Careerjet for others.
const adzunaSupported = ['at','au','be','br','ca','ch','de','es','fr','gb','in','it','mx','nl','nz','pl','ru','us','za'];
const provider = adzunaSupported.includes(countryCode) ? 'adzuna' : 'careerjet';

const localeMap = {
  'se': 'sv_SE',
  'de': 'de_DE',
  'gb': 'en_GB',
  'no': 'no_NO',
  'lk': 'en_LK',
  'fi': 'fi_FI',
  'dk': 'da_DK'
};

const localeCode = localeMap[countryCode] || 'en_GB';

return {
  country: countryCode,
  locale: localeCode,
  provider: provider,
  city: inputCity,
  original_input: inputCountry
};
